describe("graphStore — removeEntity", () => {
  it("removes the entity from the map", () => {
    const e = makeEntity("alpha");
    graphStore.upsertEntity(e);
    graphStore.removeEntity(e.id);
    expect(graphStore.entities.has(e.id)).toBe(false);
  });

  it("removes relationships connected to the removed entity", () => {
    const srcId = "org.platform.default.system.thing.src";
    const tgtId = "org.platform.default.system.thing.tgt";

    const entity = buildGraphEntity({
      id: srcId,
      properties: [],
      outgoing: [{ predicate: "knows", targetId: tgtId, confidence: 1 }],
      incoming: [],
    });
    graphStore.upsertEntity(entity);
    expect(graphStore.relationships.size).toBe(1);

    graphStore.removeEntity(srcId);
    expect(graphStore.relationships.size).toBe(0);
  });

  it("clears selectedEntityId when the selected entity is removed", () => {
    const e = makeEntity("selected");
    graphStore.upsertEntity(e);
    graphStore.selectEntity(e.id);
    expect(graphStore.selectedEntityId).toBe(e.id);

    graphStore.removeEntity(e.id);
    expect(graphStore.selectedEntityId).toBeNull();
  });

  it("does not crash when removing a non-existent entity", () => {
    expect(() => graphStore.removeEntity("nonexistent")).not.toThrow();
  });
});

